// Helper: format kết quả dạng bảng
function formatTable(
  title: string,
  result: { headers: string[]; rows: Record<string, string>[]; rowCount: number }
): string {
  if (result.rows.length === 0) {
    return `${title}\n\nKhông có dữ liệu cho khoảng thời gian này.`;
  }

  const headers = result.headers;
  const lines: string[] = [title, ""];

  // Header row
  lines.push("| " + headers.join(" | ") + " |");
  lines.push("| " + headers.map(() => "---").join(" | ") + " |");

  // Data rows
  for (const row of result.rows) {
    const values = headers.map((h) => {
      const val = row[h] ?? "";
      // Format numbers
      if (/^\d+\.\d+$/.test(val)) {
        return parseFloat(val).toFixed(2);
      }
      return val;
    });
    lines.push("| " + values.join(" | ") + " |");
  }

  lines.push("");
  lines.push(`Tổng số dòng: ${result.rowCount}`);

  return lines.join("\n");
}

// Start server
async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("GA4 MCP Server is running...");
}

main().catch((error) => {
  console.error("Failed to start server:", error);
  process.exit(1);
});

